external_knowledge:
- "sailing with a lighter anchor" metaphorically refers to regions having lower greenhouse gas emissions; 
- "emitting less greenhouse gases in 2020" is based on the calculated average emissions value;
- "economic sectors ramping up the heat with the highest inflation" metaphorically refers to sectors with the highest average inflation rates in 2020;
- "the top five sectors" are those with the highest average inflation rates, as identified by the `TopSectors` CTE.

sql:
SELECT e.id, r.name
FROM economic_data e
JOIN regions r ON e.rgn_id = r.rgn_id;

SELECT AVG(inflation_rate) AS avg_inflation_rate
FROM economic_data
WHERE unemployment_rate < 5.0;

SELECT analysis_results.model_name, analysis_results.result
FROM analysis_results
JOIN economic_data ON economic_data.id = analysis_results.id;

